//! Wasm entry: mesh-governed depth confidence for host admission gates (style transfer, etc.).

use wasm_bindgen::prelude::*;

use crate::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};
use crate::mesh_residual_deblur::{mesh_residual_deblur_rgb_f32, MeshResidualDeblurConfig};
use crate::motion_deblur::{estimate_motion_psf, motion_deblur_rgb_f32, MotionDeblurConfig};

/// Confidence + provenance JSON from [`build_mesh_depth_field`] (default config, ONNX off).
#[wasm_bindgen]
pub struct WasmMeshDepthStyleResult {
    #[wasm_bindgen(skip)]
    confidence: Vec<f32>,
    #[wasm_bindgen(skip)]
    provenance_json: String,
}

/// Result of [`wasm_mesh_residual_deblur_rgb_f32`]: reconstructed RGB,
/// admission gate, and a serde certificate for host-side inspection.
#[wasm_bindgen]
pub struct WasmMeshResidualDeblurResult {
    #[wasm_bindgen(skip)]
    rgb: Vec<f32>,
    #[wasm_bindgen(skip)]
    admission: Vec<f32>,
    #[wasm_bindgen(skip)]
    certificate_json: String,
}

#[wasm_bindgen]
impl WasmMeshResidualDeblurResult {
    #[wasm_bindgen(getter)]
    pub fn rgb(&self) -> Vec<f32> {
        self.rgb.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn admission(&self) -> Vec<f32> {
        self.admission.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn certificate_json(&self) -> String {
        self.certificate_json.clone()
    }
}

#[wasm_bindgen]
impl WasmMeshDepthStyleResult {
    #[wasm_bindgen(getter)]
    pub fn confidence(&self) -> Vec<f32> {
        self.confidence.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn provenance_json(&self) -> String {
        self.provenance_json.clone()
    }
}

/// `rgb`: row-major linear RGB in `[0,1]`, length `width * height * 3`.
/// `monocular_cue_blend`: forwarded to [`MeshDepthConfig::monocular_cue_blend`] (0 = off).
#[wasm_bindgen(js_name = wasmMeshDepthConfidenceRgbF32)]
pub fn wasm_mesh_depth_confidence_rgb_f32(
    rgb: &[f32],
    width: u32,
    height: u32,
    monocular_cue_blend: f32,
) -> Result<WasmMeshDepthStyleResult, JsError> {
    let mut cfg = MeshDepthConfig::default();
    cfg.monocular_cue_blend = monocular_cue_blend.clamp(0.0, 1.0);
    let (field, prov) = build_mesh_depth_field(rgb, width, height, &cfg, None, None)
        .map_err(|e| JsError::new(&format!("mesh_depth: {}", e)))?;
    let provenance_json =
        serde_json::to_string(&prov).map_err(|e| JsError::new(&format!("json: {}", e)))?;
    Ok(WasmMeshDepthStyleResult {
        confidence: field.confidence,
        provenance_json,
    })
}

/// Result of [`wasm_motion_deblur_rgb_f32`]: deblurred RGB, a serde certificate,
/// and diagnostic layers flattened into a manifest + concatenated f32 buffer.
#[wasm_bindgen]
pub struct WasmMotionDeblurResult {
    #[wasm_bindgen(skip)]
    rgb: Vec<f32>,
    #[wasm_bindgen(skip)]
    certificate_json: String,
    #[wasm_bindgen(skip)]
    layers_json: String,
    #[wasm_bindgen(skip)]
    layers_data: Vec<f32>,
}

#[wasm_bindgen]
impl WasmMotionDeblurResult {
    #[wasm_bindgen(getter)]
    pub fn rgb(&self) -> Vec<f32> {
        self.rgb.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn certificate_json(&self) -> String {
        self.certificate_json.clone()
    }

    /// JSON array manifest: one entry per layer with
    /// `{name,label,width,height,colormap,offset,len}` indexing into `layers_data`
    /// (offset/len in f32 elements).
    #[wasm_bindgen(getter)]
    pub fn layers_json(&self) -> String {
        self.layers_json.clone()
    }

    /// All layer planes concatenated in manifest order; each plane is
    /// `width*height` f32 in `[0,1]`.
    #[wasm_bindgen(getter)]
    pub fn layers_data(&self) -> Vec<f32> {
        self.layers_data.clone()
    }
}

/// Richardson–Lucy line-PSF motion deblur over row-major linear RGB `[0,1]`.
#[wasm_bindgen(js_name = wasmMotionDeblurRgbF32)]
pub fn wasm_motion_deblur_rgb_f32(
    rgb: &[f32],
    width: u32,
    height: u32,
    angle_deg: f32,
    length_px: f32,
    iterations: u32,
    damping: f32,
    emit_layers: bool,
) -> Result<WasmMotionDeblurResult, JsError> {
    let cfg = MotionDeblurConfig {
        angle_deg,
        length_px,
        iterations,
        damping,
        emit_layers,
    };
    let result = motion_deblur_rgb_f32(rgb, width, height, &cfg)
        .map_err(|e| JsError::new(&format!("motion_deblur: {}", e)))?;
    let certificate_json = serde_json::to_string(&result.certificate)
        .map_err(|e| JsError::new(&format!("json: {}", e)))?;

    let mut manifest = Vec::with_capacity(result.layers.len());
    let mut layers_data: Vec<f32> = Vec::new();
    for layer in &result.layers {
        let offset = layers_data.len();
        layers_data.extend_from_slice(&layer.data);
        let len = layers_data.len() - offset;
        manifest.push(serde_json::json!({
            "name": layer.name,
            "label": layer.label,
            "width": layer.width,
            "height": layer.height,
            "colormap": layer.colormap,
            "offset": offset,
            "len": len,
        }));
    }
    let layers_json = serde_json::to_string(&manifest)
        .map_err(|e| JsError::new(&format!("json: {}", e)))?;

    Ok(WasmMotionDeblurResult {
        rgb: result.rgb,
        certificate_json,
        layers_json,
        layers_data,
    })
}

/// Estimate the motion PSF `[angle_deg, length_px]` from row-major linear RGB `[0,1]`.
#[wasm_bindgen(js_name = wasmEstimateMotionPsf)]
pub fn wasm_estimate_motion_psf(rgb: &[f32], width: u32, height: u32) -> Vec<f32> {
    let (angle_deg, length_px) = estimate_motion_psf(rgb, width, height);
    vec![angle_deg, length_px]
}

/// Topology/depth-gated residual deblur over row-major linear RGB `[0,1]`.
#[wasm_bindgen(js_name = wasmMeshResidualDeblurRgbF32)]
pub fn wasm_mesh_residual_deblur_rgb_f32(
    rgb: &[f32],
    width: u32,
    height: u32,
    overpotential: f32,
    admission_floor: f32,
    saturation_limit: f32,
    depth_confidence_blend: f32,
) -> Result<WasmMeshResidualDeblurResult, JsError> {
    let mut cfg = MeshResidualDeblurConfig::default();
    cfg.overpotential = overpotential;
    cfg.admission_floor = admission_floor;
    cfg.saturation_limit = saturation_limit;
    cfg.depth_confidence_blend = depth_confidence_blend;
    let result = mesh_residual_deblur_rgb_f32(rgb, width, height, &cfg)
        .map_err(|e| JsError::new(&format!("mesh_residual_deblur: {}", e)))?;
    let certificate_json = serde_json::to_string(&result.certificate)
        .map_err(|e| JsError::new(&format!("json: {}", e)))?;
    Ok(WasmMeshResidualDeblurResult {
        rgb: result.rgb,
        admission: result.admission,
        certificate_json,
    })
}

/// Result of [`wasm_relight_monster_mesh_masked`]: relit RGB buffer.
