/// **Topological Recompositioning**: Relight using high-dimensional harmonic potential.
#[wasm_bindgen(js_name = wasmRelightMonsterMeshMasked)]
pub fn wasm_relight_monster_mesh_masked(
    rgb: &[f32],
    topology_alpha: &[f32],
    width: u32,
    height: u32,
    overpotential: f32,
    harmonic_threshold: f32,
) -> Result<WasmRelightMonsterMeshResult, JsError> {
    let mut out = vec![0.0_f32; rgb.len()];
    crate::imaging_relight::relight_monster_mesh_masked(
        &mut out,
        rgb,
        topology_alpha,
        width as usize,
        height as usize,
        overpotential,
        harmonic_threshold,
    )
    .map_err(|e| JsError::new(&e))?;
    Ok(WasmRelightMonsterMeshResult { rgb: out })
}

