/// **Manifold Calibration**: High-dimensional White/Black Balance via WASM.
#[wasm_bindgen(js_name = wasmManifoldCalibrationApply)]
pub fn wasm_manifold_calibration_apply(
    rgb: &[f32],
    topology_alpha: &[f32],
    width: u32,
    height: u32,
    r_shift: f32,
    g_shift: f32,
    b_shift: f32,
    pedestal_persistence: f32,
) -> Result<WasmTopologicalCalibrationResult, JsError> {
    let mut out = vec![0.0_f32; rgb.len()];
    crate::imaging_relight::manifold_calibration_apply(
        &mut out,
        rgb,
        topology_alpha,
        width as usize,
        height as usize,
        [r_shift, g_shift, b_shift],
        pedestal_persistence,
    )
    .map_err(|e| JsError::new(&e))?;
    Ok(WasmTopologicalCalibrationResult { rgb: out })
}

/// **Monster LUT**: 66-Chord Topological Grading via WASM.
#[wasm_bindgen(js_name = wasmMonsterLutApply)]
pub fn wasm_monster_lut_apply(
    rgb: &[f32],
    topology_alpha: &[f32],
    width: u32,
    height: u32,
    lut_66_weights: &[f32],
) -> Result<WasmTopologicalCalibrationResult, JsError> {
    if lut_66_weights.len() != 66 {
        return Err(JsError::new("monster_lut: weights must be exactly 66"));
    }
    let mut weights = [0.0_f32; 66];
    weights.copy_from_slice(lut_66_weights);

    let mut out = vec![0.0_f32; rgb.len()];
    crate::imaging_relight::monster_lut_apply(
        &mut out,
        rgb,
        topology_alpha,
        width as usize,
        height as usize,
        &weights,
    )
    .map_err(|e| JsError::new(&e))?;
    Ok(WasmTopologicalCalibrationResult { rgb: out })
}
